const crypto = require("crypto");

// Calculate deadline urgency (days until deadline)
function calculateUrgency(deadline) {
  const now = new Date();
  const deadlineDate = new Date(deadline);
  const diffTime = deadlineDate - now;
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  return diffDays;
}

// Generate immutable log hash
function generateLogHash(data) {
  return crypto.createHash("sha256").update(JSON.stringify(data)).digest("hex");
}

// Aggregate risk scores
function aggregateRisk(obligations) {
  const riskMap = { low: 1, medium: 2, high: 3, critical: 4 };
  const totalRisk = obligations.reduce((sum, ob) => sum + (riskMap[ob.risk] || 0), 0);
  return totalRisk / obligations.length;
}

return { urgency: calculateUrgency, hash: generateLogHash, risk: aggregateRisk };
